import cv2
import numpy as np
import json
import os
import math
from itertools import combinations

# --- CONFIGURATION ---
TAB_CATEGORY       = "Tab"        # Category name to measure centroids for
TAB_COLOR          = "#00AAFF"    # Overlay colour for tab contours
CENTROID_COLOR     = "#FFE800"    # Overlay colour for centroid markers
LINE_COLOR         = "#FF00FF"    # Overlay colour for distance measurement lines
TEXT_COLOR         = "#FFFFFF"    # Summary text colour
IMAGE_EXTENSIONS   = {".png", ".jpg", ".jpeg", ".tif", ".tiff", ".bmp", ".webp"}

# --- MEASUREMENT FUNCTIONS ---

def contour_from_polygon_annotation(ann):
    """Extract the largest polygon segment from a COCO polygon annotation.
    Returns an (N,1,2) int32 contour, or None if unavailable."""
    seg = ann.get("segmentation", [])
    if not isinstance(seg, list) or len(seg) == 0:
        return None
    largest = max(seg, key=lambda s: len(s))
    pts = np.array(largest, dtype=np.float64).reshape(-1, 2)
    return pts.reshape(-1, 1, 2).astype(np.int32)

def measure_centroid(contour):
    """Compute the centroid (cx, cy) of any contour using image moments.
    Returns a (float, float) tuple, or None if the contour has zero area."""
    M = cv2.moments(contour)
    if abs(M["m00"]) < 1e-6:
        return None
    cx = M["m10"] / M["m00"]
    cy = M["m01"] / M["m00"]
    return float(cx), float(cy)

def measure_centroid_distance(centroid_a, centroid_b):
    """Euclidean distance in pixels between two (cx, cy) centroid tuples."""
    dx = centroid_a[0] - centroid_b[0]
    dy = centroid_a[1] - centroid_b[1]
    return float(math.sqrt(dx * dx + dy * dy))

def contour_to_overlay_points(contour):
    """Convert an (N,1,2) contour to a plain [[x,y],...] list for overlays."""
    return [[int(p[0][0]), int(p[0][1])] for p in contour]

# --- PIPELINE (I/O, overlays, result assembly) ---

def find_image_file():
    """Find the image file in INPUT_DIR (there is always exactly one)."""
    for f in os.listdir(INPUT_DIR):
        if os.path.splitext(f)[1].lower() in IMAGE_EXTENSIONS:
            return os.path.join(INPUT_DIR, f)
    return None

def load_data():
    image_path = find_image_file()
    image = cv2.imread(image_path) if image_path else None
    with open(os.path.join(INPUT_DIR, "annotations.json")) as f:
        coco = json.load(f)
    cat_map = {c["id"]: c["name"] for c in coco["categories"]}
    return image, coco, cat_map

def write_error_result(msg):
    result = {"overlays": [], "metrics": {"error": msg}, "ctq_results": [], "stdout": msg}
    with open(os.path.join(OUTPUT_DIR, "result.json"), "w") as f:
        json.dump(result, f, indent=2)
    print(f"ERROR: {msg}")

def main():
    image, coco, cat_map = load_data()

    if image is None:
        write_error_result("Image load failed")
        return

    # ── Filter Tab annotations ───────────────────────────────────────────────
    tab_anns = [a for a in coco["annotations"] if cat_map[a["category_id"]] == TAB_CATEGORY]

    if len(tab_anns) == 0:
        write_error_result(f"No annotations found for category '{TAB_CATEGORY}'")
        return
    if len(tab_anns) < 2:
        write_error_result(f"Only 1 '{TAB_CATEGORY}' annotation found — need at least 2 to measure distance")
        return

    overlays    = []
    ctq_results = []

    # ── Extract contours and centroids for each tab ──────────────────────────
    tab_features = []   # list of dicts: {ann, contour, centroid}
    for idx, ann in enumerate(tab_anns):
        contour = contour_from_polygon_annotation(ann)
        if contour is None:
            print(f"WARNING: Could not extract contour for Tab annotation id={ann['id']}, skipping")
            continue

        centroid = measure_centroid(contour)
        if centroid is None:
            print(f"WARNING: Zero-area contour for Tab annotation id={ann['id']}, skipping")
            continue

        tab_features.append({"ann": ann, "contour": contour, "centroid": centroid, "index": idx + 1})

        # Draw the tab contour
        overlays.append({
            "type":   "contours",
            "points": contour_to_overlay_points(contour),
            "color":  TAB_COLOR,
            "label":  f"Tab {idx + 1}",
        })

        # Mark centroid with a small cross using a text label "+" 
        cx, cy = centroid
        overlays.append({
            "type": "text",
            "entries": [
                {
                    "x":    int(round(cx)) - 6,
                    "y":    int(round(cy)) + 6,
                    "text": "+",
                    "color": CENTROID_COLOR,
                    "size": 16,
                }
            ],
        })

        # One CTQ result per tab with its centroid location
        ctq_results.append({
            "feature_id": int(ann["id"]),
            "label":      f"tab_{idx + 1:03d}",
            "category":   TAB_CATEGORY,
            "measurements": {
                "centroid_x_px": round(centroid[0], 2),
                "centroid_y_px": round(centroid[1], 2),
            },
        })

    if len(tab_features) < 2:
        write_error_result("Fewer than 2 valid Tab contours — cannot compute distance")
        return

    # ── Measure centroid-to-centroid distance for all pairs ──────────────────
    pair_distances = []
    for feat_a, feat_b in combinations(tab_features, 2):
        dist = measure_centroid_distance(feat_a["centroid"], feat_b["centroid"])
        ca   = feat_a["centroid"]
        cb   = feat_b["centroid"]
        label_str = (
            f"Tab {feat_a['index']} → Tab {feat_b['index']}: {dist:.1f} px"
        )

        # Measurement line between centroids
        overlays.append({
            "type": "measurements",
            "lines": [
                {
                    "start": [float(ca[0]), float(ca[1])],
                    "end":   [float(cb[0]), float(cb[1])],
                    "value": f"{dist:.1f} px",
                    "color": LINE_COLOR,
                }
            ],
        })

        pair_distances.append({
            "tab_a_index": feat_a["index"],
            "tab_b_index": feat_b["index"],
            "tab_a_id":    int(feat_a["ann"]["id"]),
            "tab_b_id":    int(feat_b["ann"]["id"]),
            "distance_px": round(dist, 2),
        })

        # Add a pairwise CTQ result
        ctq_results.append({
            "feature_id": int(feat_a["ann"]["id"]),   # anchor to first tab in pair
            "label":      f"tab_{feat_a['index']:03d}_to_tab_{feat_b['index']:03d}",
            "category":   TAB_CATEGORY,
            "measurements": {
                "centroid_distance_px": round(dist, 2),
            },
        })

    # ── Metrics ──────────────────────────────────────────────────────────────
    all_dists = [p["distance_px"] for p in pair_distances]
    metrics = {
        "num_tabs":              int(len(tab_features)),
        "num_pairs":             int(len(pair_distances)),
        "min_centroid_dist_px":  round(min(all_dists), 2),
        "max_centroid_dist_px":  round(max(all_dists), 2),
        "avg_centroid_dist_px":  round(float(np.mean(all_dists)), 2),
    }
    # Add per-pair distance entries to metrics for easy reading
    for p in pair_distances:
        key = f"tab_{p['tab_a_index']}_to_tab_{p['tab_b_index']}_dist_px"
        metrics[key] = p["distance_px"]

    # ── Summary text overlay ─────────────────────────────────────────────────
    text_entries = [
        {"x": 20, "y": 30,  "text": "Tab Centroid Distances",
         "color": TEXT_COLOR, "size": 14},
        {"x": 20, "y": 52,  "text": f"Tabs found: {len(tab_features)}",
         "color": TAB_COLOR,  "size": 13},
    ]
    y_cursor = 72
    for p in pair_distances:
        text_entries.append({
            "x": 20, "y": y_cursor,
            "text": f"Tab {p['tab_a_index']} → Tab {p['tab_b_index']}: {p['distance_px']:.1f} px",
            "color": LINE_COLOR, "size": 13,
        })
        y_cursor += 20
    overlays.append({"type": "text", "entries": text_entries})

    # ── Stdout summary ────────────────────────────────────────────────────────
    pair_strs = [
        f"Tab {p['tab_a_index']}→Tab {p['tab_b_index']}: {p['distance_px']:.1f} px"
        for p in pair_distances
    ]
    stdout_msg = (
        f"Tab centroid distances ({len(tab_features)} tabs, {len(pair_distances)} pair(s)) | "
        + " | ".join(pair_strs)
    )

    result = {
        "overlays":    overlays,
        "metrics":     metrics,
        "ctq_results": ctq_results,
        "stdout":      stdout_msg,
    }
    with open(os.path.join(OUTPUT_DIR, "result.json"), "w") as f:
        json.dump(result, f, indent=2)
    print(stdout_msg)

main()

